#include <vector>
#include <queue>
#include <tuple>
#include <limits>
#include <algorithm>

using namespace std;

// Define a type for infinity, safely larger than any possible path cost (max path cost ~ 10^14)
constexpr long long INF = numeric_limits<long long>::max() / 2;

// Helper structure for graph edges
struct Edge {
    int to;
    long long weight;
};

// Dijkstra's algorithm implementation
// Computes shortest paths from a single source node to all other nodes
vector<long long> dijkstra(int start_node, int n, const vector<vector<Edge>>& adj) {
    vector<long long> dist(n, INF);
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;

    dist[start_node] = 0;
    pq.push({0, start_node});

    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();

        if (d > dist[u]) {
            continue;
        }

        for (const auto& edge : adj[u]) {
            int v = edge.to;
            long long weight = edge.weight;

            if (dist[u] != INF && dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}


std::vector<long long> solve(long long n_ll, std::vector<long long> prices, std::vector<std::vector<long long>> roads) {
    int n = (int)n_ll;

    // 1. Build two sets of adjacency lists: one for empty travel, one for carrying travel.
    vector<vector<Edge>> adj_empty(n);
    vector<vector<Edge>> adj_carry(n);

    for (const auto& road : roads) {
        int u = (int)road[0];
        int v = (int)road[1];
        long long cost = road[2];
        long long tax = road[3];

        // Empty travel cost is just 'cost'
        // Bidirectional
        adj_empty[u].push_back({v, cost});
        adj_empty[v].push_back({u, cost});

        // Carrying travel cost is 'cost * tax'
        // Bidirectional
        long long carry_cost = cost * tax;
        adj_carry[u].push_back({v, carry_cost});
        adj_carry[v].push_back({u, carry_cost});
    }

    // 2. Compute All-Pairs Shortest Paths (APSP) for empty travel
    // D_empty[i][j]: shortest path from i to j without apples
    vector<vector<long long>> D_empty(n, vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        D_empty[i] = dijkstra(i, n, adj_empty);
    }

    // 3. Compute APSP for carrying travel
    // D_carry[i][j]: shortest path from i to j while carrying apples
    vector<vector<long long>> D_carry(n, vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        D_carry[i] = dijkstra(i, n, adj_carry);
    }

    // 4. Calculate the final answer for each store i
    std::vector<long long> ans(n);

    for (int i = 0; i < n; ++i) {
        // Option 1: Buy directly at store i
        long long min_cost = prices[i];

        // Option 2: Travel to store j, buy apples, and return to i
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;

            // Cost = Travel i->j (empty) + Price[j] + Travel j->i (carry)

            long long empty_path_cost = D_empty[i][j];
            long long carry_path_cost = D_carry[j][i];

            // Check reachability
            if (empty_path_cost != INF && carry_path_cost != INF) {
                // Since prices[j] is up to 10^9 and paths up to 10^14, 
                // the sum fits comfortably within long long.
                long long total_cost = empty_path_cost + prices[j] + carry_path_cost;
                min_cost = std::min(min_cost, total_cost);
            }
        }
        ans[i] = min_cost;
    }

    return ans;
}

