// Type alias for adjacency list: vector of pairs (neighbor, weight)
using AdjList = vector<vector<pair<int, long long>>>;

// Dijkstra's algorithm implementation
// Returns a vector of shortest distances from the start_node
vector<long long> dijkstra(int n, const AdjList& adj, int start_node) {
    vector<long long> dist(n, INF);
    // Min-heap priority queue: stores {distance, node}
    // We use greater<> to make it a min-heap
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;

    dist[start_node] = 0;
    pq.push({0, start_node});

