                dist[v] = dist[u] + weight;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}


std::vector<long long> solve(long long n_ll, std::vector<long long> prices, std::vector<std::vector<long long>> roads) {
    int n = static_cast<int>(n_ll);

    // 1. Initialize Adjacency Lists
    // AdjE: Empty-handed travel cost (cost)
    AdjList adj_empty(n);
    // AdjF: Full-handed travel cost (cost * tax)
    AdjList adj_full(n);

    // 2. Build Graphs
    for (const auto& road : roads) {
        int u = road[0];
        int v = road[1];
        long long cost = road[2];
        long long tax = road[3];

        // Empty travel (both directions)
        adj_empty[u].push_back({v, cost});
        adj_empty[v].push_back({u, cost});

        // Full travel (both directions)
        long long full_cost = cost * tax;
        adj_full[u].push_back({v, full_cost});
        adj_full[v].push_back({u, full_cost});
    }

    // 3. Calculate Shortest Paths

    // D_empty[i][j]: Shortest path from i to j when empty-handed
    vector<vector<long long>> d_empty(n, vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        vector<long long> distances = dijkstra(n, adj_empty, i);
        for (int j = 0; j < n; ++j) {
            d_empty[i][j] = distances[j];
        }
    }

    // D_full[j][i]: Shortest path from j to i when full-handed
    // We run Dijkstra N times, starting at j, and look at the distance to i.
    vector<vector<long long>> d_full(n, vector<long long>(n));
    for (int j = 0; j < n; ++j) {
        // Distances calculated starting at j
        vector<long long> distances_from_j = dijkstra(n, adj_full, j);
        for (int i = 0; i < n; ++i) {
            d_full[j][i] = distances_from_j[i];
        }
    }

    // 4. Calculate Final Minimum Costs
    vector<long long> ans(n);

    for (int i = 0; i < n; ++i) {
        // Option 1: Buy directly at shop i
        long long min_cost = prices[i];

        // Option 2: Travel to shop j, buy, and return to i
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;

            // Cost = D_empty(i -> j) + P_j + D_full(j -> i)

            long long travel_to = d_empty[i][j];
            long long travel_back = d_full[j][i];

            // Check for unreachable paths
            if (travel_to == INF || travel_back == INF) {
                continue;
            }

            // Calculate total cost. Note that prices[j] is already long long.
            long long current_total_cost = travel_to + prices[j] + travel_back;

            min_cost = min(min_cost, current_total_cost);
